// ═══════════════════════════════════════════════════════════════════════════
// CURRENCY SYSTEM
// ═══════════════════════════════════════════════════════════════════════════
const CURRENCIES = {
  USD: { code: "USD", symbol: "$", name: "US Dollar", flag: "🇺🇸", rate: 1 },
  CNY: { code: "CNY", symbol: "¥", name: "Chinese Yuan", flag: "🇨🇳", rate: 7.25 },
  ZMW: { code: "ZMW", symbol: "K", name: "Zambian Kwacha", flag: "🇿🇲", rate: 27.5 },
  TZS: { code: "TZS", symbol: "TSh", name: "Tanzanian Shilling", flag: "🇹🇿", rate: 2650 },
};

const convertFromUSD = (usd, code) => Number(usd || 0) * CURRENCIES[code].rate;
const convertToUSD = (amt, code) => Number(amt || 0) / CURRENCIES[code].rate;

const fmtMoney = (usdAmount, code) => {
  const c = CURRENCIES[code];
  const v = convertFromUSD(usdAmount, code);
  const digits = code === "TZS" || code === "ZMW" ? 0 : 2;
  return c.symbol + v.toLocaleString("en-US", { minimumFractionDigits: digits, maximumFractionDigits: digits });
};

const fmtShort = (usdAmount, code) => {
  const c = CURRENCIES[code];
  const v = convertFromUSD(usdAmount, code);
  if (Math.abs(v) >= 1e9) return c.symbol + (v / 1e9).toFixed(1) + "B";
  if (Math.abs(v) >= 1e6) return c.symbol + (v / 1e6).toFixed(1) + "M";
  if (Math.abs(v) >= 1e3) return c.symbol + (v / 1e3).toFixed(1) + "K";
  return c.symbol + v.toFixed(0);
};

// ═══════════════════════════════════════════════════════════════════════════
// APP ROOT — routes between marketing site and dashboard
// ═══════════════════════════════════════════════════════════════════════════
const SITE_SETTINGS_KEY = "fg-site-settings-v1";
const loadSiteSettings = () => {
  try {
    const r = localStorage.getItem(SITE_SETTINGS_KEY);
    if (r) return JSON.parse(r);
  } catch (e) {}
  return { theme: "light", currency: "USD" };
};
const saveSiteSettings = (s) => {
  try { localStorage.setItem(SITE_SETTINGS_KEY, JSON.stringify(s)); } catch (e) {}
};

export default function App() {
  const [view, setView] = useState("site");
  const [settings, setSettings] = useState(() => loadSiteSettings());
  const [loaded, setLoaded] = useState(true);

  useEffect(() => { if (loaded) saveSiteSettings(settings); }, [settings, loaded]);

  // Set favicon dynamically
  useEffect(() => {
    let link = document.querySelector("link[rel~='icon']");
    if (!link) {
      link = document.createElement("link");
      link.rel = "icon";
      document.head.appendChild(link);
    }
    link.href = FAV_SRC;
    document.title = "First Grade Mineral Suppliers";
  }, []);

  const setTheme = (t) => setSettings((s) => ({ ...s, theme: t }));
  const toggleTheme = () => setSettings((s) => ({ ...s, theme: s.theme === "light" ? "dark" : "light" }));
  const setCurrency = (c) => setSettings((s) => ({ ...s, currency: c }));

  return (
    <>
      <GlobalCSS theme={settings.theme} />
      {view === "site" ? (
        <MarketingSite
          theme={settings.theme}
          currency={settings.currency}
          onToggleTheme={toggleTheme}
          onSetCurrency={setCurrency}
          onOpenDashboard={() => setView("dashboard")}
        />
      ) : (
        <Dashboard
          theme={settings.theme}
          currency={settings.currency}
          onToggleTheme={toggleTheme}
          onSetCurrency={setCurrency}
          onBackToSite={() => setView("site")}
        />
      )}
    </>
  );
}

