// ═══════════════════════════════════════════════════════════════════════════
// MARKETING SITE
// ═══════════════════════════════════════════════════════════════════════════
function MarketingSite({ theme, currency, onToggleTheme, onSetCurrency, onOpenDashboard }) {
  const [navOpen, setNavOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);
  const S = SITE_THEMES[theme];

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 40);
    window.addEventListener("scroll", onScroll);
    return () => window.removeEventListener("scroll", onScroll);
  }, []);

  const scrollTo = (id) => {
    setNavOpen(false);
    const el = document.getElementById(id);
    if (el) el.scrollIntoView({ behavior: "smooth", block: "start" });
  };

  return (
    <div style={{ background: S.bg, color: S.ink, fontFamily: "Barlow, sans-serif", transition: "background 0.3s, color 0.3s" }}>
      <SiteHeader
        S={S} theme={theme} currency={currency}
        scrolled={scrolled} navOpen={navOpen} setNavOpen={setNavOpen}
        onOpenDashboard={onOpenDashboard} scrollTo={scrollTo}
        onToggleTheme={onToggleTheme} onSetCurrency={onSetCurrency}
      />
      <Hero S={S} />
      <MineralsSection S={S} />
      <AboutSection S={S} />
      <BranchesSection S={S} />
      <GallerySection S={S} />
      <ProcessSection S={S} />
      <WhyChooseUs S={S} />
      <ContactSection S={S} />
      <SiteFooter S={S} />
    </div>
  );
}

// ────────────────────────────────────────────────────────────────────────────
// CURRENCY PICKER (used in both site header and dashboard topbar)
// ────────────────────────────────────────────────────────────────────────────
function CurrencyPicker({ currency, onSet, S, compact }) {
  const [open, setOpen] = useState(false);
  const cur = CURRENCIES[currency];

  useEffect(() => {
    const onClick = (e) => {
      if (!e.target.closest(".cur-picker")) setOpen(false);
    };
    document.addEventListener("click", onClick);
    return () => document.removeEventListener("click", onClick);
  }, []);

  return (
    <div className="cur-picker" style={{ position: "relative" }}>
      <button onClick={() => setOpen(!open)} style={{
        display: "flex", alignItems: "center", gap: 7,
        padding: compact ? "8px 12px" : "10px 14px",
        background: "transparent", border: `1px solid ${S.border}`,
        color: S.ink, fontFamily: "'Barlow Condensed', sans-serif",
        fontSize: 11, letterSpacing: 1.5, textTransform: "uppercase",
        fontWeight: 700, cursor: "pointer", borderRadius: 2,
      }}>
        <span style={{ fontSize: 14 }}>{cur.flag}</span>
        {cur.code}
        <ChevronDown size={12} />
      </button>
      {open && (
        <div style={{
          position: "absolute", top: "calc(100% + 6px)", right: 0, zIndex: 200,
          background: S.bgElev, border: `1px solid ${S.border}`, borderRadius: 3,
          boxShadow: "0 8px 24px rgba(0,0,0,0.15)", minWidth: 210, overflow: "hidden",
        }}>
          {Object.values(CURRENCIES).map((c) => (
            <button key={c.code} onClick={() => { onSet(c.code); setOpen(false); }} style={{
              display: "flex", alignItems: "center", gap: 12, width: "100%",
              padding: "12px 16px", background: currency === c.code ? S.bgAlt : "transparent",
              border: "none", borderBottom: `1px solid ${S.border}`,
              color: S.ink, fontFamily: "Barlow, sans-serif", fontSize: 13,
              cursor: "pointer", textAlign: "left", fontWeight: 500,
            }}>
              <span style={{ fontSize: 16 }}>{c.flag}</span>
              <span style={{ flex: 1 }}>
                <div style={{ fontWeight: 600 }}>{c.code} · {c.symbol}</div>
                <div style={{ fontSize: 11, color: S.inkMuted, marginTop: 2 }}>{c.name}</div>
              </span>
              {currency === c.code && <span style={{ color: S.accent }}>●</span>}
            </button>
          ))}
        </div>
      )}
    </div>
  );
}

